const a='{% block sw_data_grid_column_boolean %} <div class="sw-data-grid-column-boolean"> <mt-checkbox v-if="isInlineEdit" v-model:checked="currentValue" :disabled="disabled" /> <template v-else> <mt-icon v-if="currentValue" name="regular-checkmark-xs" size="16px" class="is--active" /> <mt-icon v-else name="regular-times-s" class="is--inactive" /> </template> </div> {% endblock %}',l={template:a,emits:["update:value"],props:{isInlineEdit:{type:Boolean,required:!1,default:!1},disabled:{type:Boolean,required:!1,default:!1},value:{required:!0}},computed:{currentValue:{get(){return this.value},set(e){this.$emit("update:value",e)}}}};export{l as default};
